// Java implementation for Android Developer Troubleshooting Part 1C
public class Main {
    public static void main(String[] args) {
        System.out.println("Executing Java process for: Android Developer Troubleshooting Part 1C");
        int result = calculateScore(85, 92);
        System.out.println("Final Score: " + result);
    }

    public static int calculateScore(int a, int b) {
        return (a + b) / 2;
    }
}
